  ('elementary-7fec267e-moex-00508', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者非屬行政訴訟法所規定的「暫時權利保護」救濟制度？', '["假扣押", "假處分", "假執行", "停止執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00509', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '有關訴願審議程序規定，下列敘述何者錯誤？', '["訴願原則上採書面審理方式進行決定", "受理訴願機關認有必要時，得通知訴願人陳述意見", "訴願人請求陳述意見時，受理訴願機關即應聽取其陳述", "訴願審議委員會主任委員無須親自聽取訴願人陳述"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00510', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何種行政訴訟種類，原則上須先踐行訴願程序？', '["課予義務訴訟", "確認訴訟", "一般給付訴訟", "公益訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00511', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '居住於新竹之甲因投資需求，向住於桃園之乙借款新臺幣 300 萬元，雙方並以書面約定若因該借貸 關係發生爭議，合意由臺灣桃園地方法院管轄。嗣後，甲因投資失利，逾期未償還向乙所借之款項， 乙乃向臺灣新竹地方法院聲請依督促程序對甲發支付命令。下列敘述何者錯誤？', '["若甲接獲支付命令後，未於20日內提出異議，該支付命令即告確定，並得為執行名義", "若甲主張支付命令上所載債權不存在而提起確認之訴，法院依債務人聲請，得許甲提供相當並確 實之擔保，停止強制執行", "甲得於支付命令確定5日後，向地方法院以欠缺管轄權為由聲請再審", "若甲接獲支付命令後第15日，提出異議但未附理由，仍屬有效之異議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00512', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於民事訴訟審級之敘述，何者錯誤？', '["對於簡易程序之第一審裁判，得上訴或抗告於管轄之高等法院，其審判以合議行之", "對於小額程序之第一審裁判，得上訴或抗告於管轄之地方法院，其審判以合議行之", "上訴經撤回或因不合法而被駁回者，原則上附帶上訴失其效力", "上訴第三審法院，非以原判決違背法令為理由，不得為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00513', 'elementary-7fec267e', 'elementary-7fec267e-moex-112-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列關於民事法院管轄之敘述，何者正確？', '["當事人得以合意定第一審及第二審管轄法院", "法院認為無管轄權者，原告與被告均得聲請以裁定移送於有管轄權之法院", "因侵權行為涉訟者，原告僅得於侵權行為地之法院起訴", "移送訴訟之聲請被駁回者，不得聲明不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:00+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
